//! Spec-compliance tests: Table Properties (ISO 29500-1 §17.4)
//!
//! These tests verify our implementation against specific OOXML table
//! property constructs.
//!
//! Fixture DOCX files are generated by `testdata/spec-compliance/tables-audit/create_docs.py`.

use stemma::{BlockNode, CanonDoc, InlineNode, TableNode, TextDirection};

use crate::common;

const FIXTURES: &str = "testdata/spec-compliance/tables-audit";

// ── helpers ──────────────────────────────────────────────────────────────
fn first_table(doc: &CanonDoc) -> &TableNode {
    doc.blocks
        .iter()
        .find_map(|b| match &b.block {
            BlockNode::Table(t) => Some(t.as_ref()),
            _ => None,
        })
        .expect("document should contain at least one table")
}

fn all_tables(doc: &CanonDoc) -> Vec<&TableNode> {
    doc.blocks
        .iter()
        .filter_map(|b| match &b.block {
            BlockNode::Table(t) => Some(t.as_ref()),
            _ => None,
        })
        .collect()
}

fn cell_text(table: &TableNode, row: usize, col: usize) -> String {
    let cell = &table.rows[row].cells[col];
    let mut text = String::new();
    for block in &cell.blocks {
        if let BlockNode::Paragraph(p) = block {
            let inlines = p.all_inlines_owned();
            for inline in &inlines {
                if let InlineNode::Text(t) = inline {
                    text.push_str(&t.text);
                }
            }
        }
    }
    text
}

// ── 1) tblLayout: fixed vs autofit (§17.4.52/§17.4.53) ─────────────────

/// ISO 29500-1 §17.4.52: tblLayout element specifies the algorithm used
/// to lay out the contents of the table (fixed or autofit).
///
/// Fixture has two tables: first with tblLayout type=fixed, second with autofit.
/// Both should parse without error.
#[test]
fn ta01_tbl_layout_parses_without_error() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "tbl-layout");
    let tables = all_tables(&doc);
    assert!(
        tables.len() >= 2,
        "should have at least 2 tables, got {}",
        tables.len()
    );
    assert_eq!(tables[0].rows.len(), 2, "table 1 should have 2 rows");
    assert_eq!(tables[1].rows.len(), 2, "table 2 should have 2 rows");
}

/// ISO 29500-1 §17.4.52: The table layout type should be preserved in the domain model.
///
/// Table 1 has tblLayout type=fixed, table 2 has type=autofit.
#[test]
fn ta01_tbl_layout_preserved_in_model() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "tbl-layout");
    let tables = all_tables(&doc);

    // Table 1: tblLayout type=fixed
    assert_eq!(
        tables[0].formatting.layout,
        Some(stemma::TableLayout::Fixed),
        "table 1 layout should be Fixed"
    );

    // Table 2: tblLayout type=autofit
    assert_eq!(
        tables[1].formatting.layout,
        Some(stemma::TableLayout::Autofit),
        "table 2 layout should be Autofit"
    );
}

// ── 2) tblCellSpacing (§17.4.44) ────────────────────────────────────────

/// ISO 29500-1 §17.4.44: tblCellSpacing specifies the default spacing
/// between cells in a table row. This is the gap between cell borders.
///
/// Fixture has a table with tblCellSpacing=100tw.
#[test]
fn ta02_tbl_cell_spacing_parses_without_error() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "tbl-cell-spacing");
    let table = first_table(&doc);
    assert_eq!(table.rows.len(), 2, "should have 2 rows");
    assert_eq!(cell_text(table, 0, 0), "Spaced A");
}

/// ISO 29500-1 §17.4.44: Cell spacing should be exposed in the domain model.
#[test]
fn ta02_tbl_cell_spacing_preserved_in_model() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "tbl-cell-spacing");
    let table = first_table(&doc);

    // When implemented: table.formatting.cell_spacing == Some(100)
    let fmt = format!("{:?}", table.formatting);
    assert!(
        fmt.contains("100"),
        "table formatting should contain cell_spacing=100tw, got: {fmt}"
    );
}

// ── 3) tblpPr — floating table positioning (§17.4.57) ──────────────────

/// ISO 29500-1 §17.4.57: tblpPr specifies positioning for a floating table
/// (anchored to text, margin, or page with offsets).
///
/// Fixture has a table with tblpPr positioning attributes.
#[test]
fn ta03_tblp_pr_parses_without_error() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "tblp-pr");
    let table = first_table(&doc);
    assert_eq!(table.rows.len(), 2, "should have 2 rows");
    assert_eq!(cell_text(table, 0, 0), "Float A");
}

/// ISO 29500-1 §17.4.57: Floating table positioning should be preserved.
#[test]
fn ta03_tblp_pr_preserved_in_model() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "tblp-pr");
    let table = first_table(&doc);

    // When implemented, something like:
    // table.formatting.positioning.vert_anchor == Some("text")
    // table.formatting.positioning.horz_anchor == Some("margin")
    // table.formatting.positioning.tblp_y == Some(1440)
    let fmt = format!("{:?}", table.formatting);
    assert!(
        fmt.contains("margin") || fmt.contains("1440"),
        "table formatting should contain positioning data from tblpPr, got: {fmt}"
    );
}

