// ── 5) Band size > 1 (§17.7.6.5/§17.7.6.7) ─────────────────────────────

/// ISO 29500-1 §17.7.6.5/§17.7.6.7: tblStyleRowBandSize > 1 means
/// multiple consecutive rows share the same band.
///
/// Fixture: rowBandSize=2, 6 data rows, no first/last row flags.
/// Expected: rows 0-1 = band1 (BDD7EE), rows 2-3 = band2 (F8CBAD),
///           rows 4-5 = band1 (BDD7EE).
#[test]
fn ta05_band_size_gt1_parses_without_error() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "band-size-gt1");
    let table = first_table(&doc);
    assert_eq!(table.rows.len(), 6, "should have 6 rows");
}

/// Band1Horz (blue BDD7EE) should apply to rows 0-1 when rowBandSize=2.
#[test]
fn ta05_band_size_gt1_rows_0_1_band1() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "band-size-gt1");
    let table = first_table(&doc);

    for row_idx in 0..2 {
        let shading = table.rows[row_idx].cells[0]
            .formatting
            .shading
            .as_ref()
            .unwrap_or_else(|| {
                panic!("row {row_idx}: should have band1Horz shading (BDD7EE) with rowBandSize=2")
            });
        assert_eq!(
            shading.fill.as_deref(),
            Some("BDD7EE"),
            "row {row_idx}: band1Horz should be blue BDD7EE"
        );
    }
}

/// Band2Horz (orange F8CBAD) should apply to rows 2-3 when rowBandSize=2.
#[test]
fn ta05_band_size_gt1_rows_2_3_band2() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "band-size-gt1");
    let table = first_table(&doc);

    for row_idx in 2..4 {
        let shading = table.rows[row_idx].cells[0]
            .formatting
            .shading
            .as_ref()
            .unwrap_or_else(|| {
                panic!("row {row_idx}: should have band2Horz shading (F8CBAD) with rowBandSize=2")
            });
        assert_eq!(
            shading.fill.as_deref(),
            Some("F8CBAD"),
            "row {row_idx}: band2Horz should be orange F8CBAD"
        );
    }
}

/// Band1Horz (blue BDD7EE) should wrap back to rows 4-5 when rowBandSize=2.
#[test]
fn ta05_band_size_gt1_rows_4_5_band1_again() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "band-size-gt1");
    let table = first_table(&doc);

    for row_idx in 4..6 {
        let shading = table.rows[row_idx].cells[0]
            .formatting
            .shading
            .as_ref()
            .unwrap_or_else(|| panic!(
                "row {row_idx}: should have band1Horz shading (BDD7EE) with rowBandSize=2 (cycle)"
            ));
        assert_eq!(
            shading.fill.as_deref(),
            Some("BDD7EE"),
            "row {row_idx}: band1Horz should cycle back to blue BDD7EE"
        );
    }
}

// ── 6) Width types: dxa, pct, auto, nil (§17.4.84) ──────────────────────

/// ISO 29500-1 §17.4.84: tblW specifies the total width of the table.
/// The type attribute can be: dxa (twips), pct (50ths of %), auto, nil.
///
/// Fixture has 4 tables with each width type.
#[test]
fn ta06_width_types_parse_without_error() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "width-types");
    let tables = all_tables(&doc);
    assert!(
        tables.len() >= 4,
        "should have 4 tables, got {}",
        tables.len()
    );
}

/// Table 1: width type=dxa, w=5000.
#[test]
fn ta06_width_dxa() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "width-types");
    let tables = all_tables(&doc);
    let w = tables[0]
        .formatting
        .width
        .as_ref()
        .expect("table 1 should have width (type=dxa)");
    assert_eq!(w.w, 5000, "table 1 width value should be 5000");
    assert_eq!(
        w.width_type,
        stemma::domain::WidthType::Dxa,
        "table 1 width type should be dxa"
    );
}

