// ── 8) Cell width type=pct (§17.4.87) ───────────────────────────────────

/// ISO 29500-1 §17.4.87: tcW can specify cell width as pct (50ths of %).
///
/// Fixture: 3 columns with widths 1250 (25%), 2500 (50%), 1250 (25%).
#[test]
fn ta08_cell_width_pct_parses_without_error() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "cell-width-pct");
    let table = first_table(&doc);
    assert_eq!(table.rows.len(), 2, "should have 2 rows");
    assert_eq!(table.rows[0].cells.len(), 3, "should have 3 columns");
}

/// Cell widths in pct should be preserved in cell formatting.
#[test]
fn ta08_cell_width_pct_values() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "cell-width-pct");
    let table = first_table(&doc);

    let widths: Vec<_> = table.rows[0]
        .cells
        .iter()
        .map(|c| c.formatting.width.as_ref())
        .collect();

    let w0 = widths[0].expect("cell 0 should have width");
    assert_eq!(
        w0.width_type,
        stemma::domain::WidthType::Pct,
        "cell 0 width type should be pct"
    );
    assert_eq!(w0.w, 1250, "cell 0 width should be 1250 (25%)");

    let w1 = widths[1].expect("cell 1 should have width");
    assert_eq!(
        w1.width_type,
        stemma::domain::WidthType::Pct,
        "cell 1 width type should be pct"
    );
    assert_eq!(w1.w, 2500, "cell 1 width should be 2500 (50%)");

    let w2 = widths[2].expect("cell 2 should have width");
    assert_eq!(
        w2.width_type,
        stemma::domain::WidthType::Pct,
        "cell 2 width type should be pct"
    );
    assert_eq!(w2.w, 1250, "cell 2 width should be 1250 (25%)");
}

// ── 9) Nested table structure (§17.4.38) ─────────────────────────────────

/// ISO 29500-1 §17.4.38: Tables can be nested inside table cells.
///
/// Fixture: 2x2 outer table with 2x2 inner table in cell (1,0).
#[test]
fn ta09_nested_table_parses_without_error() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "nested-table");
    let table = first_table(&doc);
    assert_eq!(table.rows.len(), 2, "outer table should have 2 rows");
}

/// The nested table should appear as a Table block in cell (1,0).
#[test]
fn ta09_nested_table_in_cell() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "nested-table");
    let outer = first_table(&doc);

    let cell_10 = &outer.rows[1].cells[0];
    let inner_tables: Vec<&TableNode> = cell_10
        .blocks
        .iter()
        .filter_map(|b| match b {
            BlockNode::Table(t) => Some(t.as_ref()),
            _ => None,
        })
        .collect();

    assert_eq!(
        inner_tables.len(),
        1,
        "cell (1,0) should contain exactly 1 nested table, got {}",
        inner_tables.len()
    );
}

/// The nested table should have correct structure (2x2) and content.
#[test]
fn ta09_nested_table_content() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "nested-table");
    let outer = first_table(&doc);

    let cell_10 = &outer.rows[1].cells[0];
    let inner = cell_10
        .blocks
        .iter()
        .find_map(|b| match b {
            BlockNode::Table(t) => Some(t.as_ref()),
            _ => None,
        })
        .expect("cell (1,0) should contain a nested table");

    assert_eq!(inner.rows.len(), 2, "inner table should have 2 rows");
    assert_eq!(
        inner.rows[0].cells.len(),
        2,
        "inner table row 0 should have 2 cells"
    );

    // Check inner table content
    let inner_text_00 = {
        let cell = &inner.rows[0].cells[0];
        let mut text = String::new();
        for block in &cell.blocks {
            if let BlockNode::Paragraph(p) = block {
                for inline in p.all_inlines() {
                    if let InlineNode::Text(t) = inline {
                        text.push_str(&t.text);
                    }
                }
            }
        }
        text
    };
    assert!(
        inner_text_00.contains("Inner R0C0"),
        "inner table cell (0,0) should contain 'Inner R0C0', got: '{inner_text_00}'"
    );
}

// ── 10) Cell properties: noWrap, textDirection, tcFitText (§17.4.30/72/63) ─

/// ISO 29500-1 §17.4.30: noWrap — cell content does not wrap.
/// Fixture cell (0,0) has <w:noWrap/> (true, no val attribute).
#[test]
fn ta10_cell_no_wrap_true() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "cell-props");
    let table = first_table(&doc);
    assert_eq!(
        table.rows[0].cells[0].formatting.no_wrap,
        Some(true),
        "cell (0,0): noWrap should be true (element present without val)"
    );
}

/// ISO 29500-1 §17.4.72: textDirection — text flow direction in cell.
/// Fixture cell (0,1) has <w:textDirection w:val="tbRl"/>.
#[test]
fn ta10_cell_text_direction_tbrl() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "cell-props");
    let table = first_table(&doc);
    assert_eq!(
        table.rows[0].cells[1].formatting.text_direction,
        Some(TextDirection::TbRl),
        "cell (0,1): textDirection should be TbRl"
    );
}

/// ISO 29500-1 §17.4.63: tcFitText — fit text to cell width.
/// Fixture cell (1,0) has <w:tcFitText/> (true, no val attribute).
#[test]
fn ta10_cell_tc_fit_text_true() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "cell-props");
    let table = first_table(&doc);
    assert_eq!(
        table.rows[1].cells[0].formatting.tc_fit_text,
        Some(true),
        "cell (1,0): tcFitText should be true (element present without val)"
    );
}

/// Cell (1,1) has noWrap=false, textDirection=btLr, tcFitText=false.
/// Verifies that explicit false values and alternate text directions
/// are correctly parsed.
#[test]
fn ta10_cell_combined_props() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "cell-props");
    let table = first_table(&doc);
    let cell = &table.rows[1].cells[1];

    assert_eq!(
        cell.formatting.no_wrap,
        Some(false),
        "cell (1,1): noWrap w:val=\"0\" should be false"
    );
    assert_eq!(
        cell.formatting.text_direction,
        Some(TextDirection::BtLr),
        "cell (1,1): textDirection should be BtLr"
    );
    assert_eq!(
        cell.formatting.tc_fit_text,
        Some(false),
        "cell (1,1): tcFitText w:val=\"0\" should be false"
    );
}

/// Cells without these properties should have None values.
#[test]
fn ta10_cell_props_absent_is_none() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "cell-props");
    let table = first_table(&doc);

    // Cell (0,0) only has noWrap, should not have textDirection or tcFitText
    assert_eq!(
        table.rows[0].cells[0].formatting.text_direction, None,
        "cell (0,0): textDirection should be None when absent"
    );
    assert_eq!(
        table.rows[0].cells[0].formatting.tc_fit_text, None,
        "cell (0,0): tcFitText should be None when absent"
    );

    // Cell (0,1) only has textDirection, should not have noWrap or tcFitText
    assert_eq!(
        table.rows[0].cells[1].formatting.no_wrap, None,
        "cell (0,1): noWrap should be None when absent"
    );
    assert_eq!(
        table.rows[0].cells[1].formatting.tc_fit_text, None,
        "cell (0,1): tcFitText should be None when absent"
    );

    // Cell (1,0) only has tcFitText, should not have noWrap or textDirection
    assert_eq!(
        table.rows[1].cells[0].formatting.no_wrap, None,
        "cell (1,0): noWrap should be None when absent"
    );
    assert_eq!(
        table.rows[1].cells[0].formatting.text_direction, None,
        "cell (1,0): textDirection should be None when absent"
    );
}
